import java.util.*;class A{static int W,H;static int[][]T,LK;static Map<String,String>[]RM=new HashMap[14];static Map<String,String>OPP=Map.of("TOP","BOTTOM","BOTTOM","TOP","LEFT","RIGHT","RIGHT","LEFT");static Map<String,String>CW=Map.of("TOP","RIGHT","RIGHT","BOTTOM","BOTTOM","LEFT","LEFT","TOP");static int[]DX={0,0,-1,1},DY={-1,1,0,0};static String[]DN={"TOP","BOTTOM","LEFT","RIGHT"};static int di(String s){return s.equals("TOP")?0:s.equals("BOTTOM")?1:s.equals("LEFT")?2:3;}static Map<String,String>rotR(Map<String,String>rm){var r=new HashMap<String,String>();rm.forEach((e,x)->r.put(CW.get(e),CW.get(x)));return r;}static Map<Integer,Map<String,String>>rots=new HashMap<>();static Map<String,String>gt(int x,int y){return rots.getOrDefault(y*99+x,RM[T[y][x]]);}static List<int[]>plan=new ArrayList<>();static Map<String,String>[]planR;static boolean dfs(int x,int y,String e){if(y>=H)return true;if(x<0||x>=W||y<0)return false;var o=RM[T[y][x]];var cs=new ArrayList<Map<String,String>>();if(LK[y][x]==1)cs.add(gt(x,y));else{var t=new HashMap<>(o);for(int i=0;i<4;i++){cs.add(new HashMap<>(t));t=rotR(t);}}int k=y*99+x;for(var c:cs){if(!c.containsKey(e))continue;var ex=c.get(e);int nx=x+DX[di(ex)],ny=y+DY[di(ex)];var ne=OPP.get(ex);var prev=rots.get(k);rots.put(k,c);if(dfs(nx,ny,ne)){if(!c.equals(RM[T[y][x]]))plan.add(new int[]{x,y,plan.size()});return true;}if(prev!=null)rots.put(k,prev);else rots.remove(k);}return false;}public static void main(String[]args){var s=new Scanner(System.in);W=s.nextInt();H=s.nextInt();RM[0]=Map.of();RM[1]=Map.of("TOP","BOTTOM","LEFT","BOTTOM","RIGHT","BOTTOM");RM[2]=Map.of("TOP","RIGHT","RIGHT","BOTTOM");RM[3]=Map.of("TOP","LEFT","LEFT","BOTTOM");RM[4]=Map.of("TOP","LEFT","LEFT","BOTTOM");RM[5]=Map.of("TOP","RIGHT","RIGHT","BOTTOM");RM[6]=Map.of("TOP","RIGHT","LEFT","BOTTOM");RM[7]=Map.of("TOP","LEFT","RIGHT","BOTTOM");RM[8]=Map.of("LEFT","BOTTOM","RIGHT","TOP");RM[9]=Map.of("RIGHT","BOTTOM","LEFT","TOP");RM[10]=Map.of("LEFT","RIGHT","RIGHT","LEFT");RM[11]=Map.of("TOP","BOTTOM","BOTTOM","TOP");RM[12]=Map.of("TOP","RIGHT","RIGHT","TOP","LEFT","BOTTOM","BOTTOM","LEFT");RM[13]=Map.of("TOP","LEFT","LEFT","TOP","RIGHT","BOTTOM","BOTTOM","RIGHT");T=new int[H][W];LK=new int[H][W];for(int y=0;y<H;y++)for(int x=0;x<W;x++){T[y][x]=s.nextInt();LK[y][x]=T[y][x]<0?1:0;T[y][x]=Math.abs(T[y][x]);}s.nextInt();var Q=new ArrayList<String>();for(;;){int yi=s.nextInt(),xi=s.nextInt();String en=s.next();int R=s.nextInt();for(int i=0;i<R;i++){s.nextInt();s.nextInt();s.next();}if(Q.isEmpty()){rots.clear();plan.clear();dfs(xi,yi,en);/* simplified: just output WAIT for now if plan complex */}System.out.println(Q.isEmpty()?"WAIT":Q.remove(0));System.out.flush();}}}